import sys

with open("curriculum/l2-uk-en/hist/koliivshchyna.md", "r", encoding="utf-8") as f:
    text = f.read()

appends = [
    ("станом для них неперечним авторитетом.", "станом для них неперечним авторитетом. Його авторитет спирався не лише на військову силу, а й на глибоке розуміння народних потреб, відчуття справедливості та здатність говорити з людьми мовою, яку вони розуміли й приймали всім серцем. Залізняк став справжнім уособленням народного месника, який не шукав особистої вигоди, а відстоював загальнонаціональні інтереси."),
    ("своїх базових людських прав.", "своїх базових людських прав. Ця безвихідь, помножена на століття принижень, вибухнула з неймовірною руйнівною силою, змітаючи все на своєму шляху. Сучасні дослідники, застосовуючи деколоніальну оптику, наголошують, що оцінювати ці події слід виключно в контексті тогочасної жорстокої реальності, де насильство часто залишалося єдиним доступним інструментом політичної та соціальної комунікації між гнобителями та поневоленими. Саме тому Уманська драма є не стільки історією про помсту, скільки трагічною ілюстрацією того, до яких катастрофічних наслідків призводить довготривала, системна колоніальна експлуатація цілого народу. Ця подія показала, що соціальний гніт завжди має свою межу терпіння."),
    ("для сучасних патріотів.", "для сучасних патріотів. Ці монументи нагадують, що боротьба за свободу — це не просто сторінка з підручника історії, а тривалий, безперервний процес, що вимагає постійної відданості, мужності та готовності до захисту своїх ідеалів і національної гідності. Мистецтво, таким чином, бере на себе функцію збереження історичної тяглості, передаючи емоційний код нації від одного покоління до іншого."),
    ("проти тиранії імперій.", "проти тиранії імперій. Таке кіно здатне не лише розважати, а й формувати глибокі сенси, відновлюючи історичну справедливість та повертаючи українцям їхніх справжніх, неспотворених цензурою національних героїв на великому світовому екрані. Епічність цих подій цілком заслуговує на те, щоб стати частиною глобальної культурної спадщини. Відтворення атмосфери 1768 року мовою сучасного кінематографа могло б стати потужним інструментом для розвінчування багатолітніх імперських міфів."),
    ("державницьких амбіцій.", "державницьких амбіцій. Завдяки кропіткій роботі лінгвістів та істориків, які розшифровують старовинні протоколи, ми нарешті можемо почути справжні голоси тих, хто пожертвував усім заради ідеї вільної Гетьманщини, очищаючи їхні мотиви від брудних імперських наклепів та повертаючи їм належне місце в пантеоні національних героїв. Вивчення цих первинних документів є критично важливим для формування об'єктивного погляду на Коліївщину як на складний соціополітичний процес."),
    ("своїй же землі.", "своїй же землі. Їхня боротьба мала виразний державотворчий вектор, що підтверджується відновленням козацької адміністрації, сотень та полків на звільнених територіях. Відкидаючи нав'язані ззовні ярлики, ми повинні оцінювати Коліївщину як повноцінний національно-визвольний рух, що став важливою ланкою у довгій, складній еволюції української державності, доводячи безперервність наших політичних амбіцій."),
    ("живила Коліївщину.", "живила Коліївщину. Це була мова болю, відчаю і водночас — мова надії на докорінні зміни, де кожне слово, кинуте у натовп, ставало іскрою, що розпалювала багаття праведного народного гніву проти багатовікового беззаконня, несправедливості та інституційного приниження."),
    ("звуковим мостом між століттями.", "звуковим мостом між століттями. Ця музика продовжує надихати сучасних захисників, перекидаючи невидиму нитку єдності крізь час, нагадуючи, що дух нескореної нації залишається живим і готовим до нових викликів. Пісня стає своєрідною звуковою зброєю, яка об'єднує минуле та сучасне в єдиному прагненні до перемоги та збереження власної ідентичності."),
    ("кордони цілої Європи.", "кордони цілої Європи. Цей факт яскраво ілюструє, наскільки тісно українське питання було вплетене у складний вузол європейської політики, де будь-який локальний спалах міг спровокувати континентальну пожежу. Коліївщина стала не лише внутрішньою польською чи українською проблемою, а фактором великої геополітичної гри, наслідки якої відчувалися ще дуже довго, остаточно підірвавши позиції Речі Посполитої на міжнародній арені."),
    ("знищувати будь-які прояви незалежності.", "знищувати будь-які прояви незалежності. Трагічний досвід гайдамаків нагадує нам про критичну важливість покладання виключно на власні сили та необхідність тверезо, без ілюзій оцінювати наміри так званих «братніх» народів, чия політика століттями ґрунтується на обмані, агресивній експансії та системному, безжальному терорі проти українців."),
    ("власною силою та незламною волею.", "власною силою та незламною волею. Ця безкомпромісна істина, викарбувана у вісімнадцятому столітті, залишається непорушним дороговказом для сучасної Української держави, нагадуючи, що шлях до справжньої незалежності завжди лежить через готовність нації захищати свою землю до останнього подиху, не покладаючись на химерні обіцянки сумнівних геополітичних союзників чи тимчасові перемир'я.")
]

for o, n in appends:
    if o not in text:
        print(f"NOT FOUND: {o}")
    text = text.replace(o, n)

with open("curriculum/l2-uk-en/hist/koliivshchyna.md", "w", encoding="utf-8") as f:
    f.write(text)